package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreEmptyLinesTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreEmptyLines(true);
        assertNotNull(format);
        assertTrue(format.getIgnoreEmptyLines());
        assertEquals(CSVFormat.DEFAULT.getDelimiter(), format.getDelimiter());
        assertEquals(CSVFormat.DEFAULT.getQuoteCharacter(), format.getQuoteCharacter());
    }

    @Test
    void testWithIgnoreEmptyLinesFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreEmptyLines(false);
        assertNotNull(format);
        assertFalse(format.getIgnoreEmptyLines());
        assertEquals(CSVFormat.DEFAULT.getDelimiter(), format.getDelimiter());
        assertEquals(CSVFormat.DEFAULT.getQuoteCharacter(), format.getQuoteCharacter());
    }

    @Test
    void testWithIgnoreEmptyLinesDoesNotAffectOriginal() {
        CSVFormat original = CSVFormat.DEFAULT;
        boolean originalValue = original.getIgnoreEmptyLines();
        CSVFormat modified = original.withIgnoreEmptyLines(!originalValue);
        assertNotSame(original, modified);
        assertEquals(originalValue, original.getIgnoreEmptyLines());
        assertEquals(!originalValue, modified.getIgnoreEmptyLines());
    }
}
